SELECT AVG(gdp_per_capita) AS average_gdp_per_capita
FROM economic_data
WHERE unemployment_rate > 4.0;

SELECT MAX(median_household_income) AS max_median_household_income
FROM counties
WHERE state = 'Alabama';

SELECT AVG(median_household_income) AS average_median_household_income
FROM economic_data
WHERE year = (SELECT MAX(year) FROM economic_data);
